import com.github.benmanes.caffeine.cache.*;
import io.micrometer.core.instrument.*;
import org.springframework.stereotype.*;
import org.springframework.data.redis.core.RedisTemplate;
import java.util.concurrent.TimeUnit;

@Service
public class TwoLevelProductCache {
    private final Cache<String, String> l1;
    private final RedisTemplate<String, String> redis;
    private final Counter l1Hits, l2Hits, dbHits;
    private final ProductRepository repo;

    TwoLevelProductCache(MeterRegistry reg, RedisTemplate<String, String> r, ProductRepository p) {
        redis = r; repo = p;
        l1 = Caffeine.newBuilder().maximumSize(1000).expireAfterWrite(30, TimeUnit.SECONDS).build();
        l1Hits = reg.counter("cache.hits", "level", "l1");
        l2Hits = reg.counter("cache.hits", "level", "l2");
        dbHits = reg.counter("cache.hits", "level", "db");
    }

    public String getProduct(String id) {
        // L1: Caffeine (in-process, ~0.1ms)
        String v = l1.getIfPresent(id);
        if (v != null) { l1Hits.increment(); return v; }

        // L2: Redis (network, ~1ms)
        v = redis.opsForValue().get("product:" + id);
        if (v != null) { l2Hits.increment(); l1.put(id, v); return v; }

        // DB: PostgreSQL (disk, ~5ms)
        v = repo.findNameById(id);
        dbHits.increment();
        redis.opsForValue().set("product:" + id, v, 5, TimeUnit.MINUTES);
        l1.put(id, v);
        return v;
    }

    interface ProductRepository { String findNameById(String id); }
}

import com.github.benmanes.caffeine.cache.*;
import org.springframework.stereotype.*;
import org.springframework.transaction.annotation.Transactional;
import org.springframework.data.redis.core.RedisTemplate;
import org.springframework.boot.test.context.SpringBootTest;
import org.springframework.beans.factory.annotation.Autowired;
import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.*;

@Service
class ProductWriteService {
    private final Cache<String, String> l1;
    private final RedisTemplate<String, String> redis;
    ProductWriteService(Cache<String, String> l1, RedisTemplate<String, String> r){this.l1=l1;redis=r;}

    @Transactional
    public void updateProduct(String id, String newValue) {
        // DELETE from cache BEFORE writing to DB:
        // If we write to DB then delete: a concurrent read between write+delete
        // would cache the old value and serve it for the full TTL.
        // Delete first: concurrent reads go to DB (get fresh value) → repopulate cache.
        l1.invalidate(id);              // L1: immediate
        redis.delete("product:" + id); // L2: distributed
        // Then write to DB:
        // productRepo.save(new Product(id, newValue));
        System.out.println("Product " + id + " updated. Cache invalidated.");
    }
}

@SpringBootTest
class WriteInvalidationTest {
    @Autowired TwoLevelProductCache cache;
    @Autowired ProductWriteService writeService;

    @Test void update_invalidatesCache() {
        // Populate cache:
        cache.l1.put("PROD-001", "old-name");
        assertNotNull(cache.l1.getIfPresent("PROD-001"));

        // Update product:
        writeService.updateProduct("PROD-001", "new-name");

        // L1 should be invalidated:
        assertNull(cache.l1.getIfPresent("PROD-001"), "L1 should be invalidated after write");
    }
}

import org.springframework.data.redis.core.RedisTemplate;
import org.springframework.stereotype.Service;
import java.util.concurrent.TimeUnit;

@Service
public class StampedeProtectedCache {
    private final RedisTemplate<String, String> redis;
    StampedeProtectedCache(RedisTemplate<String, String> r) { redis = r; }

    public String getOrLoad(String id, java.util.function.Supplier<String> loader) {
        String cacheKey = "product:" + id;
        String lockKey  = "product:lock:" + id;

        // Check cache first:
        String cached = redis.opsForValue().get(cacheKey);
        if (cached != null) return cached;

        // Cache miss: acquire distributed lock (SETNX = SET if Not eXists)
        Boolean locked = redis.opsForValue().setIfAbsent(lockKey, "1", 10, TimeUnit.SECONDS);

        if (Boolean.TRUE.equals(locked)) {
            // This thread won the lock: load from DB
            try {
                String value = loader.get();  // DB call
                redis.opsForValue().set(cacheKey, value, 5, TimeUnit.MINUTES);
                return value;
            } finally {
                redis.delete(lockKey);  // release lock
            }
        } else {
            // Another thread is loading: wait briefly then read from cache
            try { Thread.sleep(50); } catch (InterruptedException e) { Thread.currentThread().interrupt(); }
            String result = redis.opsForValue().get(cacheKey);
            return result != null ? result : loader.get();  // fallback if still not cached
        }
    }

    // WITHOUT PROTECTION:
    // 1000 concurrent requests for PROD-001 when cache expires:
    // All 1000 miss L1 and L2
    // All 1000 hit DB simultaneously → DB spike → 1000 slow queries
    // DB might crash under load
    //
    // WITH LOCK: only 1 hits DB, others wait 50ms and read from fresh cache
}

