@Service
class ProductCacheableService {
    interface ProductRepo { String findNameById(String id); }
    private final ProductRepo repo;
    ProductCacheableService(ProductRepo r){repo=r;}

    @Cacheable(value="products", key="#id")
    public String getProduct(String id){
        return repo.findNameById(id);  // only called on cache miss
    }

    @CacheEvict(value="products", key="#id")
    public void updateProduct(String id, String name){
        System.out.println("Updating " + id + " → " + name);
        // repo.save(new Product(id, name));
    }
