@SpringBootTest
class SpringCacheTest {
    @Autowired ProductCacheableService svc;
    @MockBean ProductCacheableService.ProductRepo repo;
    @BeforeEach void reset(){ reset(repo); }
    @Test void cacheable_callsRepoOnce(){
        when(repo.findNameById("P1")).thenReturn("iPhone 15");
        svc.getProduct("P1"); svc.getProduct("P1");  // second call: cached
        verify(repo, times(1)).findNameById("P1");   // DB called only once!
    }
    @Test void cacheEvict_clears(){
        when(repo.findNameById("P2")).thenReturn("MacBook");
        svc.getProduct("P2");   // populate cache
        svc.updateProduct("P2","MacBook Pro");  // evict
        svc.getProduct("P2");   // cache miss → repo called again
        verify(repo, times(2)).findNameById("P2");  // called twice (before + after evict)
    }
}

