@Service
public class CacheWarmupService {
    private static final Logger log = LoggerFactory.getLogger(CacheWarmupService.class);
    private final Cache<String, String> merchantCache;
    boolean warmedUp = false;

    CacheWarmupService() {
        merchantCache = Caffeine.newBuilder().maximumSize(200).expireAfterWrite(5, TimeUnit.MINUTES).build();
    }

    @EventListener(ApplicationStartedEvent.class)
    public void warmUp() {
        long start = System.currentTimeMillis();
        log.info("[Cache Warm-up] Loading top merchants...");

        // Simulate loading top 100 merchants:
        List<String> topMerchants = loadTopMerchants();
        topMerchants.forEach(id -> merchantCache.put(id, "Merchant-" + id));

        long elapsed = System.currentTimeMillis() - start;
        log.info("[Cache Warm-up] Complete: {} merchants loaded in {}ms",
            topMerchants.size(), elapsed);
        warmedUp = true;
    }

    private List<String> loadTopMerchants() {
        // In production: repo.findTop100ByOrderByTransactionCountDesc()
        List<String> merchants = new ArrayList<>();
        for (int i = 1; i <= 100; i++) merchants.add("MRC-" + String.format("%03d", i));
        return merchants;
    }

    public boolean isWarmedUp() { return warmedUp; }
    public long cacheSize() { return merchantCache.estimatedSize(); }
}

