import com.github.benmanes.caffeine.cache.*;
import org.springframework.stereotype.*;
import org.springframework.transaction.annotation.Transactional;
import java.util.concurrent.TimeUnit;
import org.springframework.boot.test.context.SpringBootTest;
import org.springframework.beans.factory.annotation.Autowired;
import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.*;

@Service
class MerchantConfigCache {
    private final Cache<String, String> l1 =
        Caffeine.newBuilder().maximumSize(500).expireAfterWrite(5, TimeUnit.MINUTES).build();

    public String get(String merchantId) {
        return l1.get(merchantId, id -> loadFromDb(id));  // Caffeine's load-on-miss
    }

    @Transactional
    public void update(String merchantId, String config) {
        // WRITE-THROUGH: update DB + cache simultaneously
        // DB write:
        saveToDb(merchantId, config);
        // Cache write (same transaction):
        l1.put(merchantId, config);  // immediately visible to all threads
        // No cache invalidation needed: new value directly in cache
    }

    // WRITE-THROUGH vs CACHE-ASIDE WRITE:
    // Cache-aside write: update DB, then DELETE from cache (next read repopulates)
    //   Gap: between delete and next read, cache is empty → DB hit for first read
    //   Use for: infrequent updates, don't mind brief cache miss after write
    //
    // Write-through: update DB AND cache simultaneously
    //   No gap: new value immediately in cache → no cache miss after write
    //   Complexity: cache and DB updated in same transaction
    //   Use for: high-read config data that must be immediately consistent

    private String loadFromDb(String id) { return "default-config-" + id; }
    private void saveToDb(String id, String v) { System.out.println("DB: " + id + "=" + v); }
}

@SpringBootTest
class WriteThroughTest {
    @Autowired MerchantConfigCache cache;
    @Test void update_reflectsInGet(){
        cache.update("MRC-001", "plan=gold");
        assertEquals("plan=gold", cache.get("MRC-001"));
    }
}

