// GRAFANA CACHE MONITORING DASHBOARD

// Panel 1: L1 Hit Rate (Gauge from recordStats)
// PromQL: caffeine_hit_rate{cache='products'}
// Shows: hit rate 0-1 over time
// Alert: < 0.7 for 5 min → cache too small or TTL too short

// Panel 2: Cache hits by level (stacked counters)
// PromQL (one per series): rate(cache_hits_total{level='l1'}[5m])  → L1 hits/sec
//                          rate(cache_hits_total{level='l2'}[5m])  → L2 hits/sec
//                          rate(cache_hits_total{level='db'}[5m])  → DB hits/sec
// Stacked bar: shows what % of requests hit each level
// Target: l1=40%, l2=55%, db=5% (adjust cache sizes if DB% is high)

// Panel 3: L2 hit rate (calculated)
// PromQL:
//   rate(cache_hits_total{level='l2'}[5m])
//   / (
//     rate(cache_hits_total{level='l2'}[5m]) +
//     rate(cache_hits_total{level='db'}[5m])
//   ) * 100
// = L2 hit rate %: l2 hits / (l2 hits + db hits)
// Alert: < 80% for 10 minutes

// Panel 4: Cache size (Caffeine gauge)
// PromQL: caffeine_cache_size{cache='products'}
// Shows: how full the cache is
// Alert: ≥ maximumSize × 0.95 → approaching eviction (increase cache or reduce data)

// Prometheus alert:
public class CacheAlerts {
    static String L2_LOW_HIT_RATE = """
        - alert: L2CacheHitRateLow
          expr: |
            rate(cache_hits_total{level='l2'}[5m])
            / (rate(cache_hits_total{level='l2'}[5m]) + rate(cache_hits_total{level='db'}[5m]))
            < 0.80
          for: 10m
          annotations:
            summary: 'L2 cache hit rate < 80% for 10 min — cache too small or TTL too short'
    """;
    public static void main(String[] a) {
        System.out.println("Cache dashboard: L1%, L2%, DB% hits over time");
    }
}

