@Service
public class GatewayConfigCache {
    private final Cache<String,String> l1;
    private final Counter l1Hits,l1Misses;
    private volatile int warmedCount=0;

    GatewayConfigCache(MeterRegistry r){
        l1=Caffeine.newBuilder().maximumSize(500).expireAfterWrite(5,TimeUnit.MINUTES).recordStats().build();
        Gauge.builder("gateway.cache.hitrate",l1,c->c.stats().hitRate()).register(r);
        Gauge.builder("gateway.cache.size",l1,c->(double)c.estimatedSize()).register(r);
        l1Hits=Counter.builder("gateway.cache.l1.hits").register(r);
        l1Misses=Counter.builder("gateway.cache.l1.misses").register(r);
    }

    @EventListener(ApplicationStartedEvent.class)
    public void warmUp(){
        for(int i=1;i<=100;i++){
            l1.put("gateway:"+i, "config:{timeout:3000,retries:3}");
            warmedCount++;
        }
    }

